import { prisma } from './lib/prisma';

// Cursor-based pagination
async function cursorPaginate(cursor?: string) {
  const take = 20;
  const posts = await prisma.post.findMany({
    take: take + 1,
    ...(cursor && { skip: 1, cursor: { id: cursor } }),
    orderBy: [{ createdAt: 'desc' }, { id: 'asc' }],
  });
  const hasMore = posts.length > take;
  const data = hasMore ? posts.slice(0, take) : posts;
  return {
    data,
    nextCursor: hasMore ? data[data.length - 1].id : null,
  };
}

// Offset-based pagination
async function offsetPaginate(page = 1, size = 20) {
  const [data, total] = await prisma.$transaction([
    prisma.post.findMany({ skip: (page - 1) * size, take: size }),
    prisma.post.count(),
  ]);
  return { data, total, totalPages: Math.ceil(total / size) };
}

