import { Prisma } from '@prisma/client';
import { prisma } from './lib/prisma';

// Reusable validated select fragment
const userBasicSelect = Prisma.validator<
  Prisma.UserSelect
>()({
  id: true,
  name: true,
  email: true,
});

// Reusable validated include fragment
